"use client";

import { useState, useId } from "react";
import Image from "next/image";
import { Share2 } from "lucide-react";
import copy from "copy-to-clipboard";
import { useParams } from "next/navigation";
import { formatPrice } from "@/utils/polymarketTrading";

type TradingHeaderProps = {
  marketTitle?: string | null;
  symbolImageUrl?: string;
  currentYesPrice: number;
  totalVolume?: number;
  /** Optional label after volume (e.g. "USDC") */
  volumeLabel?: string;
  onBack?: () => void;
  onGenerateClick?: () => void;
  isGenerating?: boolean;
  countdown?: number | null;
  hasGenerated?: boolean;
  ready?: boolean;
  canGenerate?: boolean;
};

function GenerateButtonImage({ className }: { className?: string }) {
  const patternId = `pattern-gen-${useId().replace(/:/g, "")}`;
  return (
    <svg
      width="195"
      height="38"
      viewBox="0 0 487 91"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      xmlnsXlink="http://www.w3.org/1999/xlink"
    >
      <rect width="487" height="91" fill={`url(#${patternId})`} />
      <defs>
        <pattern
          id={patternId}
          patternContentUnits="objectBoundingBox"
          width="1"
          height="1"
        >
          <use
            xlinkHref="#image0_40_3"
            transform="matrix(0.00205339 0 0 0.010989 -0.334702 -5.92308)"
          />
        </pattern>
        <image
          id="image0_40_3"
          width="800"
          height="1200"
          preserveAspectRatio="none"
          xlinkHref="data:image/png;base64,"
        />
      </defs>
    </svg>
  );
}

function GeneratedButtonImage({ className }: { className?: string }) {
  const patternId = `pattern-done-${useId().replace(/:/g, "")}`;
  return (
    <svg
      width="152"
      height="42"
      viewBox="0 0 380 104"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      xmlnsXlink="http://www.w3.org/1999/xlink"
    >
      <rect width="380" height="104" fill={`url(#${patternId})`} />
      <defs>
        <pattern
          id={patternId}
          patternContentUnits="objectBoundingBox"
          width="1"
          height="1"
        >
          <use
            xlinkHref="#image0_40_2"
            transform="matrix(0.00263158 0 0 0.00961538 -0.560526 -5.09615)"
          />
        </pattern>
        <image
          id="image0_40_2"
          width="800"
          height="1200"
          preserveAspectRatio="none"
          xlinkHref="data:image/png;base64,"
        />
      </defs>
    </svg>
  );
}

export default function TradingHeader({
  marketTitle,
  symbolImageUrl,
  currentYesPrice,
  totalVolume,
  volumeLabel,
  onBack,
  onGenerateClick,
  isGenerating,
  countdown,
  hasGenerated,
  ready,
  canGenerate,
}: TradingHeaderProps) {
  const [showTooltip, setShowTooltip] = useState(false);
  const params = useParams();

  const handleShareClick = () => {
    // Get event slug from URL params
    const eventSlug = params?.event as string | undefined;

    if (!eventSlug) {
      // Fallback to current page URL if no slug found
      const currentUrl = window.location.href;
      const copied = copy(currentUrl);
      if (copied) {
        setShowTooltip(true);
        setTimeout(() => setShowTooltip(false), 2000);
      }
      return;
    }

    // Construct event detail page URL
    const baseUrl = window.location.origin;
    const eventDetailUrl = `${baseUrl}/rexmarkets/polymarket/${encodeURIComponent(eventSlug)}`;

    const copied = copy(eventDetailUrl);
    if (copied) {
      setShowTooltip(true);
      setTimeout(() => setShowTooltip(false), 2000);
    }
  };

  return (
    <>
      {onBack && (
        <div className="flex-shrink-0 px-3 sm:px-4 py-2.5 sm:py-3 border-b border-white/10">
          <button
            onClick={onBack}
            className="flex items-center gap-2 text-white/60 hover:text-white transition-colors text-sm"
            aria-label="Back to table"
          >
            <svg
              width="16"
              height="16"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
            >
              <path d="M19 12H5M12 19l-7-7 7-7" />
            </svg>
            <span className="text-sm">Back to Markets</span>
          </button>
        </div>
      )}

      <div className="flex-shrink-0 px-3 sm:px-4 py-3 border-b border-white/10">
        <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
          {/* Top row on mobile: image + title + share. On desktop: same plus share on right */}
          <div className="flex items-center gap-3 min-w-0 flex-1">
            {symbolImageUrl && (
              <Image
                src={symbolImageUrl}
                alt={marketTitle || "Market"}
                width={40}
                height={40}
                className="rounded flex-shrink-0 w-9 h-9 sm:w-10 sm:h-10"
                unoptimized
              />
            )}
            <div className="min-w-0 flex-1">
              <div className="flex items-start justify-between gap-2">
                <h1 className="text-base sm:text-lg font-bold text-[#ffc000] truncate leading-tight">
                  {marketTitle}
                </h1>
                <div className="relative flex-shrink-0 sm:hidden">
                  <button
                    type="button"
                    onClick={handleShareClick}
                    className="flex items-center justify-center w-9 h-9 transition-all text-white/60 hover:text-[#ffc000] cursor-pointer -m-1"
                    aria-label="Share market link"
                  >
                    <Share2 className="w-5 h-5" />
                  </button>
                  {showTooltip && (
                    <div className="absolute bottom-full right-0 mb-2 px-3 py-1.5 bg-black/90 border border-[#ffc000] text-[#ffc000] text-xs rounded-md whitespace-nowrap z-10">
                      Link Copied
                    </div>
                  )}
                </div>
              </div>
              <div className="flex items-center gap-2 mt-1 flex-wrap">
                <span className="text-xs sm:text-sm text-white/60">
                  {Number.isFinite(currentYesPrice)
                    ? `${formatPrice(currentYesPrice)}`
                    : "—"}
                </span>
                <span className="text-xs sm:text-sm text-red-400">
                  {Number.isFinite(currentYesPrice) && currentYesPrice > 0
                    ? `-${((currentYesPrice - 0.75) * 100).toFixed(2)}%`
                    : "—"}
                </span>
                <span className="text-xs sm:text-sm text-white/60 truncate">
                  Vol:{" "}
                  {typeof totalVolume === "number" &&
                  Number.isFinite(totalVolume)
                    ? totalVolume.toLocaleString()
                    : "0"}
                  {volumeLabel ? ` ${volumeLabel}` : ""}
                </span>
              </div>
            </div>
            {/* Generate button: desktop only, inside left block (between title and share) */}
            {onGenerateClick && (
              <div className="hidden sm:flex flex-shrink-0">
                {isGenerating && countdown !== null ? (
                  <div className="flex flex-col items-center justify-center py-1.5 px-3 rounded-lg bg-[#1a1a1a] border border-white/10">
                    <div className="text-[#FFD700] font-bold text-sm animate-pulse">
                      {countdown}s
                    </div>
                  </div>
                ) : hasGenerated ? (
                  <div className="flex items-center justify-center">
                    <GeneratedButtonImage className="w-4 h-4 shrink-0" />
                  </div>
                ) : (
                  <button
                    type="button"
                    onClick={onGenerateClick}
                    disabled={isGenerating || !ready || !canGenerate}
                    className={`flex items-center justify-center transition-all ${
                      isGenerating || !ready || !canGenerate
                        ? "cursor-not-allowed opacity-50"
                        : "hover:opacity-90 active:scale-[0.98]"
                    }`}
                    aria-label="Generate News Intelligence"
                  >
                    <GenerateButtonImage className="w-4 h-4 shrink-0" />
                  </button>
                )}
              </div>
            )}
          </div>

          {/* Share: desktop only, rightmost */}
          <div className="relative hidden sm:block flex-shrink-0">
            <button
              type="button"
              onClick={handleShareClick}
              className="flex items-center justify-center w-10 h-10 transition-all text-white/60 hover:text-[#ffc000] cursor-pointer"
              aria-label="Share market link"
            >
              <Share2 className="w-5 h-5" />
            </button>
            {showTooltip && (
              <div className="absolute bottom-full right-0 mb-2 px-3 py-1.5 bg-black/90 border border-[#ffc000] text-[#ffc000] text-xs rounded-md whitespace-nowrap z-10">
                Link Copied
              </div>
            )}
          </div>

          {/* Generate button: mobile only, full width below */}
          {onGenerateClick && (
            <div className="w-full sm:hidden">
              {isGenerating && countdown !== null ? (
                <div className="flex flex-col items-center justify-center py-2 px-3 rounded-lg bg-[#1a1a1a] border border-white/10 w-full">
                  <div className="text-[#FFD700] font-bold text-sm animate-pulse">
                    {countdown}s
                  </div>
                </div>
              ) : hasGenerated ? (
                <div className="flex items-center justify-center w-full pt-1 pb-2">
                  <GeneratedButtonImage className="h-9 w-auto max-w-[152px] object-contain" />
                </div>
              ) : (
                <button
                  type="button"
                  onClick={onGenerateClick}
                  disabled={isGenerating || !ready || !canGenerate}
                  className={`w-full flex items-center justify-center transition-all py-1 ${
                    isGenerating || !ready || !canGenerate
                      ? "cursor-not-allowed opacity-50"
                      : "hover:opacity-90 active:scale-[0.98]"
                  }`}
                  aria-label="Generate News Intelligence"
                >
                  <GenerateButtonImage className="h-9 w-auto max-w-[195px] object-contain" />
                </button>
              )}
            </div>
          )}
        </div>
      </div>
    </>
  );
}
